sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	var grConfiguredAction, grConfiguredParam, configuredActionSysID;
	var currentParamSysID = current.getUniqueValue();
	var currentParamKey = current.getValue('key');
	var parentPackageSysID = current.getValue('package');

	if (!currentParamKey) {
		gs.warn('Tanium Action Package Parameter with sys_id ' + currentParamSysID + ' created without a key. This should not generally happen. This might be worth investigating.');
		return;
	}

	grConfiguredAction = new GlideRecord('x_taniu_tan_core_configured_action_package');

	//Query to find any "Configured Actions" (active or not) using this param's parent package.
	grConfiguredAction.addQuery('action_package', parentPackageSysID);
	grConfiguredAction.query();

	/* For each Configured Action found:
		1. Check if a Configured Param already exists with this key.
		2. If found, update the "package_parameter" field to point to this new param.
		3. If no existing params with this new param's key are found, then create a new one.
		4. Repeat for each Configured Action associated with this param's parent Action Package.
	*/
	while (grConfiguredAction.next()) {
		configuredActionSysID = grConfiguredAction.getUniqueValue();

		grConfiguredParam = new GlideRecord(
			'x_taniu_tan_core_configured_action_parameter'
		);
		grConfiguredParam.addQuery(
			'configured_action',
			configuredActionSysID
		);
		grConfiguredParam.addQuery(
			'key',
			currentParamKey
		);
		//Set limit of 1 since only one param can exist with a given key per package, and thus
		// only one configured param can exist with that key per configured action.
		grConfiguredParam.setLimit(1);
		grConfiguredParam.query();

		if (grConfiguredParam.next()) {
			grConfiguredParam.setValue('package_parameter', currentParamSysID);
			grConfiguredParam.update();
			continue; //Continue to next loop, skip the below code.
		}

		//Existing configured param with this new param's key not found associated with this
		// configured action, so create one.
		grConfiguredParam.initialize();
		grConfiguredParam.setValue(
			'package_parameter',
			current.getUniqueValue()
		);
		grConfiguredParam.setValue(
			'configured_action',
			configuredActionSysID
		);
		grConfiguredParam.setValue(
			'key',
			currentParamKey
		);
		grConfiguredParam.insert();
	}

})(current, previous);
